import React, { useState, useEffect } from "react";
import { Button, Container, Row, Col, Card, Alert, Spinner, Form } from "react-bootstrap";
import { useNavigate, useParams } from "react-router-dom";
import api from "../services/api"; 
import { createOrder } from "../services/orderService"; 
import { getUserFromLocalStorage } from "../services/authService"; 

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [ticketTypes, setTicketTypes] = useState([]);
  const [quantities, setQuantities] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [totalTickets, setTotalTickets] = useState(0);  // Tổng số vé
  const [totalAmount, setTotalAmount] = useState(0);    // Tổng tiền
  const [walletAddress, setWalletAddress] = useState("");

  useEffect(() => {
    const fetchEventData = async () => {
      try {
        setLoading(true);
        const response = await api.get(`/users/events/${id}`);
        if (response.data?.success) {
          setEvent(response.data.data);
        } else {
          setError("Không tìm thấy sự kiện này");
        }

        const ticketResponse = await api.get(`/users/events/${id}/ticket-types`);
        if (ticketResponse.data?.success) {
          setTicketTypes(ticketResponse.data.data?.ticket_types || []);
        }

        // Kiểm tra ví người dùng đã được liên kết chưa
        const user = getUserFromLocalStorage();
        if (user?.walletAddress) {
          setWalletAddress(user.walletAddress);
        } else {
          setError("Bạn cần liên kết ví trước khi đặt vé.");
        }

      } catch (err) {
        console.error("Lỗi khi tải dữ liệu sự kiện:", err);
        setError("Có lỗi xảy ra khi tải dữ liệu sự kiện.");
      } finally {
        setLoading(false);
      }
    };

    fetchEventData();
  }, [id]);

  const handleQuantityChange = (ticketId, value) => {
    let quantity = Number(value);
    if (quantity < 0) quantity = 0;

    const ticket = ticketTypes.find((ticket) => ticket.id === ticketId);
    if (quantity > ticket?.quantity_available) quantity = ticket?.quantity_available;

    setQuantities((prev) => ({ ...prev, [ticketId]: quantity }));
  };

  useEffect(() => {
    const total = ticketTypes.reduce((sum, ticket) => {
      const qty = quantities[ticket.id] || 0;
      return sum + qty;
    }, 0);
    setTotalTickets(total);

    const amount = ticketTypes.reduce((sum, ticket) => {
      const qty = quantities[ticket.id] || 0;
      return sum + qty * (ticket.price || 0);
    }, 0);
    setTotalAmount(amount);
  }, [ticketTypes, quantities]);

  const handleCreateOrder = async () => {
    if (!walletAddress) {
      setError("Bạn cần liên kết ví trước khi đặt vé.");
      return;
    }

    const items = ticketTypes
      .filter((ticket) => quantities[ticket.id] > 0)
      .map((ticket) => ({
        ticket_type_id: ticket.id,
        quantity: quantities[ticket.id],
      }));

    if (items.length === 0) {
      setError("Vui lòng chọn ít nhất một vé.");
      return;
    }

    try {
      const response = await createOrder({ items, walletAddress });
      if (response?.data?.success) {
        navigate(`/payment/${response.data.data.orderId}`);
      } else {
        setError("Không thể tạo đơn hàng.");
      }
    } catch (err) {
      setError("Lỗi khi tạo đơn hàng.");
    }
  };

  if (loading) {
    return <Spinner animation="border" variant="primary" />;
  }

  if (error) {
    return <Alert variant="danger">{error}</Alert>;
  }

  return (
    <Container>
      <Row>
        <Col md={8}>
          <Card>
            <Card.Img variant="top" src={event?.banner_image || "/images/default-banner.jpg"} />
            <Card.Body>
              <Card.Title>{event?.title}</Card.Title>
              <Card.Text>{event?.description}</Card.Text>
              <Button onClick={() => navigate("/home")}>Trở về</Button>
            </Card.Body>
          </Card>
        </Col>

        <Col md={4}>
          <Card>
            <Card.Body>
              <Card.Title>Thông tin sự kiện</Card.Title>
              <Card.Text><strong>Địa điểm:</strong> {event?.location}</Card.Text>
              <Card.Text><strong>Ngày diễn ra:</strong> {new Date(event?.event_date).toLocaleDateString("vi-VN")}</Card.Text>
              <div>
                {ticketTypes.map((ticket) => (
                  <div key={ticket.id}>
                    <h5>{ticket.name}</h5>
                    <input
                      type="number"
                      min="0"
                      max={ticket.quantity_available}
                      value={quantities[ticket.id] || 0}
                      onChange={(e) => handleQuantityChange(ticket.id, e.target.value)}
                    />
                    <span>{ticket.price.toLocaleString("vi-VN")} đ</span>
                  </div>
                ))}
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <div className="order-summary">
        <h4>Tổng số vé: {totalTickets}</h4>
        <h4>Tổng tiền: {totalAmount.toLocaleString("vi-VN")} đ</h4>
        <Button onClick={handleCreateOrder} disabled={totalTickets === 0}>
          Tạo đơn hàng
        </Button>
      </div>
    </Container>
  );
}

export default EventDetailPage;
